evaluators.evaluation_logic:
const checkpoints = [];

const caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorites') || '[]');

// Filter qualifying restaurant/food branding case studies from 2022+
const qualifyingCaseStudies = caseStudies.filter(cs => {
  const isRestaurant = cs.industry === 'restaurant' || cs.industry === 'food_beverage';
  const yearOk = typeof cs.year === 'number' && cs.year >= 2022;
  const hasBranding = Array.isArray(cs.service_types) && cs.service_types.indexOf('branding') !== -1;
  return isRestaurant && yearOk && hasBranding;
});

// Find the newest one by published_at
let newest = null;
qualifyingCaseStudies.forEach(cs => {
  if (!newest) {
    newest = cs;
    return;
  }
  const dCur = cs.published_at ? new Date(cs.published_at) : new Date(0);
  const dBest = newest.published_at ? new Date(newest.published_at) : new Date(0);
  if (dCur > dBest) {
    newest = cs;
  }
});

const favoritedCaseStudyIds = favorites
  .filter(f => f.item_type === 'case_study')
  .map(f => f.item_id);

// CP1 (0.4): User favorited at least one qualifying restaurant/food branding case study from 2022+
const qualifyingIds = qualifyingCaseStudies.map(cs => cs.id);
const qualifyingFavoritedIds = qualifyingIds.filter(id => favoritedCaseStudyIds.indexOf(id) !== -1);
checkpoints.push({ passed: qualifyingFavoritedIds.length > 0, weight: 0.4 });

// CP2 (0.6): User favorited specifically the newest qualifying case study
const newestFavorited = !!newest && favoritedCaseStudyIds.indexOf(newest.id) !== -1;
checkpoints.push({ passed: !!newest && newestFavorited, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const snapshotRaw = localStorage.getItem('task2_checkoutSummarySnapshot');
const snapshot = snapshotRaw ? JSON.parse(snapshotRaw) : null;

const cartId = snapshot && snapshot.cart_id ? snapshot.cart_id : (cart && cart.id ? cart.id : null);
const itemsForCart = cartId ? cartItems.filter(ci => ci.cart_id === cartId) : [];

const findProduct = (id) => products.find(p => p.id === id);

// Qualifying website template items in this cart
const qualifyingCartItems = itemsForCart.filter(ci => {
  const p = findProduct(ci.product_id);
  if (!p) return false;
  const isWebsiteTemplate = p.product_category === 'website_templates';
  const hasSubcat = p.product_subcategory === 'ecommerce' || p.product_subcategory === 'portfolio';
  const priceOk = typeof p.price === 'number' && p.price < 60;
  const ratingOk = typeof p.rating === 'number' && p.rating >= 4.0;
  return isWebsiteTemplate && hasSubcat && priceOk && ratingOk;
});

let hasEcommerce = false;
let hasPortfolio = false;
qualifyingCartItems.forEach(ci => {
  const p = findProduct(ci.product_id);
  if (!p) return;
  if (p.product_subcategory === 'ecommerce') hasEcommerce = true;
  if (p.product_subcategory === 'portfolio') hasPortfolio = true;
});

// CP1 (0.6): Checkout summary snapshot exists for a cart that has at least one qualifying ecommerce AND one qualifying portfolio template
const cp1Passed = !!snapshot && !!cartId && hasEcommerce && hasPortfolio;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.4): That cart has exactly two qualifying website template line items (one ecommerce, one portfolio)
const qualifyingCount = qualifyingCartItems.length;
const cp2Passed = cp1Passed && qualifyingCount === 2;
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');
const projectRequests = JSON.parse(localStorage.getItem('project_requests') || '[]');

// Qualifying branding packages under 5000 that include logo + brand guidelines
const qualifyingPackages = servicePackages.filter(sp => sp.service_type === 'branding' && sp.is_active && typeof sp.price === 'number' && sp.price < 5000 && !!sp.includes_logo_design && !!sp.includes_brand_guidelines);

let cheapestPrice = null;
qualifyingPackages.forEach(sp => {
  if (cheapestPrice === null || sp.price < cheapestPrice) cheapestPrice = sp.price;
});
const cheapestPackages = qualifyingPackages.filter(sp => sp.price === cheapestPrice);
const cheapestIds = cheapestPackages.map(sp => sp.id);

const includesPhrase = (text, phrase) => {
  if (!text || !phrase) return false;
  return String(text).toLowerCase().indexOf(String(phrase).toLowerCase()) !== -1;
};

// Project requests that target any qualifying package, with budget <5000 and both phrases in description
const qualifyingRequests = projectRequests.filter(pr => {
  const pkgOk = qualifyingPackages.some(sp => sp.id === pr.package_id);
  const budgetOk = typeof pr.budget === 'number' && pr.budget < 5000;
  const desc = pr.project_description || '';
  const hasLogo = includesPhrase(desc, 'logo design');
  const hasGuidelines = includesPhrase(desc, 'brand guidelines');
  return pkgOk && budgetOk && hasLogo && hasGuidelines;
});

// CP1 (0.4): User submitted at least one qualifying request (correct package type, budget, and mentions both deliverables)
const cp1Passed = qualifyingRequests.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.6): At least one such request targets the cheapest qualifying package
const cp2Passed = qualifyingRequests.some(pr => cheapestIds.indexOf(pr.package_id) !== -1);
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const cartId = cart && cart.id ? cart.id : null;
const itemsForCart = cartId ? cartItems.filter(ci => ci.cart_id === cartId) : [];

const findProduct = (id) => products.find(p => p.id === id);

// Qualifying merchandise items in cart
const qualifyingItems = itemsForCart.filter(ci => {
  const p = findProduct(ci.product_id);
  if (!p) return false;
  const isMerch = p.product_category === 'merchandise';
  const priceOk = typeof p.price === 'number' && p.price < 35;
  const freeShip = !!p.free_shipping;
  return isMerch && priceOk && freeShip;
});

const distinctProductIds = Array.from(new Set(qualifyingItems.map(ci => ci.product_id)));
const hasThreeDistinct = distinctProductIds.length >= 3;
const hasBlue = qualifyingItems.some(ci => ci.selected_color === 'blue');

// CP1 (0.6): At least three distinct qualifying merchandise products in the cart
checkpoints.push({ passed: hasThreeDistinct, weight: 0.6 });

// CP2 (0.4): Among those qualifying items, at least one has selected_color blue
checkpoints.push({ passed: hasThreeDistinct && hasBlue, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const posts = JSON.parse(localStorage.getItem('blog_posts') || '[]');
const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// Qualifying UX case study posts from 2023+ (tagged ux/user_experience)
const qualifyingPosts = posts.filter(p => {
  if (!p.published_at) return false;
  const year = new Date(p.published_at).getFullYear();
  const hasTag = Array.isArray(p.tags) && (p.tags.indexOf('ux') !== -1 || p.tags.indexOf('user_experience') !== -1);
  return year >= 2023 && p.category === 'ux_case_study' && hasTag;
});
const titlesLc = qualifyingPosts.map(p => String(p.title || '').toLowerCase());

const countMentionedTitles = (notes) => {
  if (!notes) return 0;
  const noteLc = String(notes).toLowerCase();
  const mentioned = new Set();
  titlesLc.forEach(t => {
    if (t && noteLc.indexOf(t) !== -1) {
      mentioned.add(t);
    }
  });
  return mentioned.size;
};

let passed = false;
subs.forEach(sub => {
  if (passed) return;
  if (sub.frequency !== 'monthly') return;
  if (!Array.isArray(sub.interests) || sub.interests.indexOf('design_tips') === -1) return;
  const mentionedCount = countMentionedTitles(sub.notes || '');
  if (mentionedCount >= 2) {
    passed = true;
  }
});

// Single checkpoint (1.0): Correct subscription plus notes referencing two qualifying UX case studies
checkpoints.push({ passed, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const favorites = JSON.parse(localStorage.getItem('favorites') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

const findProduct = (id) => products.find(p => p.id === id);

// Products that are favorited and meet all criteria
const qualifyingFavProducts = favorites
  .filter(f => f.item_type === 'product')
  .map(f => {
    const p = findProduct(f.item_id);
    if (!p) return null;
    const isDigital = p.product_category === 'digital_downloads';
    const priceOk = typeof p.price === 'number' && p.price <= 25;
    const ratingOk = typeof p.rating === 'number' && p.rating >= 4.5;
    return (isDigital && priceOk && ratingOk) ? p : null;
  })
  .filter(p => !!p);

const distinctProductIds = Array.from(new Set(qualifyingFavProducts.map(p => p.id)));
const distinctCreators = Array.from(new Set(qualifyingFavProducts.map(p => p.creator_name)));

const hasFourProducts = distinctProductIds.length >= 4;
const hasThreeCreators = distinctCreators.length >= 3;

// CP1 (0.6): At least four distinct qualifying digital download products favorited
checkpoints.push({ passed: hasFourProducts, weight: 0.6 });

// CP2 (0.4): Those qualifying favorites come from at least three different creators
checkpoints.push({ passed: hasFourProducts && hasThreeCreators, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
const projectPlans = JSON.parse(localStorage.getItem('project_plans') || '[]');
const viewedRaw = localStorage.getItem('task7_viewedCaseStudies');
const viewed = viewedRaw ? JSON.parse(viewedRaw) : null;

const industries = ['healthcare', 'fintech', 'education'];
const qualifyingByIndustry = {};
industries.forEach(ind => {
  qualifyingByIndustry[ind] = caseStudies.filter(cs => {
    if (cs.industry !== ind) return false;
    if (!Array.isArray(cs.service_types) || cs.service_types.indexOf('mobile_app_design') === -1) return false;
    if (typeof cs.year !== 'number' || cs.year < 2021 || cs.year > 2024) return false;
    return true;
  });
});

let viewedAll = true;
const selectedCaseStudies = {};
industries.forEach(ind => {
  if (!viewedAll) return;
  const entry = viewed && viewed[ind];
  if (!entry || !entry.case_study_id) {
    viewedAll = false;
    return;
  }
  const list = qualifyingByIndustry[ind] || [];
  const cs = list.find(c => c.id === entry.case_study_id);
  if (!cs) {
    viewedAll = false;
    return;
  }
  selectedCaseStudies[ind] = cs;
});

// CP1 (0.5): Instrumentation shows a qualifying viewed case study for each industry
checkpoints.push({ passed: viewedAll, weight: 0.5 });

// CP2 (0.5): A project plan exists for Sept 2025, budget_range 50_000_75_000, whose description mentions all three selected case study titles
let planPassed = false;
if (viewedAll && Array.isArray(projectPlans)) {
  projectPlans.forEach(pp => {
    if (planPassed) return;
    if (!pp.target_launch_date || !pp.budget_range || !pp.description) return;
    const d = new Date(pp.target_launch_date);
    if (isNaN(d.getTime())) return;
    const year = d.getUTCFullYear();
    const month = d.getUTCMonth(); // 0-based
    if (year !== 2025 || month !== 8) return; // September
    if (pp.budget_range !== '50_000_75_000') return;

    const descLc = String(pp.description).toLowerCase();
    let allTitlesPresent = true;
    industries.forEach(ind => {
      const cs = selectedCaseStudies[ind];
      if (!cs) {
        allTitlesPresent = false;
        return;
      }
      const titleLc = String(cs.title || '').toLowerCase();
      if (!titleLc || descLc.indexOf(titleLc) === -1) {
        allTitlesPresent = false;
      }
    });

    if (allTitlesPresent) {
      planPassed = true;
    }
  });
}

checkpoints.push({ passed: planPassed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const promoCodes = JSON.parse(localStorage.getItem('promo_codes') || '[]');

// All qualifying UI kit bundles
const qualifyingProducts = products.filter(p => {
  if (p.product_category !== 'ui_kits') return false;
  if (p.product_subcategory !== 'ui_kit_bundles') return false;
  if (!p.is_bundle) return false;
  const priceOk = typeof p.price === 'number' && p.price >= 40 && p.price <= 120;
  const ratingOk = typeof p.rating === 'number' && p.rating >= 4.0;
  const desktopOk = !!p.includes_desktop_layouts;
  const mobileOk = !!p.includes_mobile_layouts;
  return priceOk && ratingOk && desktopOk && mobileOk;
});

let cheapestPrice = null;
qualifyingProducts.forEach(p => {
  if (cheapestPrice === null || p.price < cheapestPrice) cheapestPrice = p.price;
});
const cheapestProducts = qualifyingProducts.filter(p => p.price === cheapestPrice);
const cheapestIds = cheapestProducts.map(p => p.id);

const cartId = cart && cart.id ? cart.id : null;
const itemsForCart = cartId ? cartItems.filter(ci => ci.cart_id === cartId) : [];

const hasCheapestInCart = cheapestProducts.length > 0 && itemsForCart.some(ci => cheapestIds.indexOf(ci.product_id) !== -1);

// CP1 (0.6): Cart contains at least one of the cheapest qualifying UI kit bundles
checkpoints.push({ passed: hasCheapestInCart, weight: 0.6 });

// Check for applied 10%-off promo on this cart
let tenPercentPromoApplied = false;
if (hasCheapestInCart && cart && cart.applied_promo_code_id) {
  const promo = promoCodes.find(p => p.id === cart.applied_promo_code_id);
  if (promo && promo.active && promo.discount_type === 'percentage' && promo.discount_value === 10) {
    tenPercentPromoApplied = true;
  }
}

// CP2 (0.4): A 10%-off percentage promo is applied on the same cart that contains the cheapest qualifying bundle
checkpoints.push({ passed: hasCheapestInCart && tenPercentPromoApplied, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
